    expect(plan.summary.retainedCount).toBe(3);
    expect(plan.summary.deletedCount).toBe(2);
    expect(plan.summary.spaceReclaimedBytes).toBe(200);
    expect(plan.summary.spaceRetainedBytes).toBe(300);
