}

function buildArgs(cfg: RunConfig): string[] {
  const args: string[] = ["--input", cfg.input];
  if (cfg.now) args.push("--now", cfg.now);
  if (cfg.maxAgeDays !== undefined) {
    args.push("--max-age-days", String(cfg.maxAgeDays));
